function defaultRolesForProtectedAction(action: string): string[] {
  if (/scratch/i.test(action)) return ['racing-secretary', 'veterinarian'];
  if (/vet|veterinary/i.test(action)) return ['veterinarian'];
  if (/steward|discipline|official-results|modify-official/i.test(action)) return ['steward'];
  if (/payout/i.test(action)) return ['finance'];
  if (/security|emergency/i.test(action)) return ['security'];
  if (/gate|distance|configuration|race-start|race-stop/i.test(action)) return ['racing-secretary', 'track-superintendent'];
  if (/surface|track-closure|track-reopen|irrigation|harrow|rolling/i.test(action)) return ['track-superintendent'];
  if (/compliance/i.test(action)) return ['compliance-officer'];
  return ['admin'];
}

function approvalBoundaryPayload<T extends Record<string, unknown>>(input: T, context: NexusApiClientContext = {}): T & { tenantId: string; racetrackId: string; actorId: string; actorType: 'human'; roles: string[]; evidence: string[] } {
  const action = String(input.action ?? 'safety-critical-control');
  const target = String(input.target ?? 'protected-target');
  const actor = String(input.actorId ?? input.actor ?? 'frontend-operator');
  const roles = Array.isArray(input.roles) && input.roles.length ? input.roles.map(String) : defaultRolesForProtectedAction(action);
  const evidence = Array.isArray(input.evidence) && input.evidence.length ? input.evidence.map(String) : ['frontend-request', `target:${target}`];
  return {
    ...input,
    tenantId: String(input.tenantId ?? context.tenantId ?? 'trackmind'),
    racetrackId: String(input.racetrackId ?? context.racetrackId ?? 'main-track'),
    actorId: actor,
    actorType: 'human',
    roles,
    evidence,
  };
}

async function errorPayload(res: Response): Promise<{ code?: string; message?: string; details?: string[]; requestId?: string; timestamp?: string } | undefined> {
  try {
    const body = typeof res.json === 'function' ? await res.json() as { error?: { code?: string; message?: string; details?: string[]; requestId?: string; timestamp?: string } } : undefined;
    return body?.error;
  } catch {
    return undefined;
  }
}

function responseHeader(res: Response, name: string) {
  try {
    return typeof res.headers?.get === 'function' ? res.headers.get(name) ?? undefined : undefined;
  } catch {
    return undefined;
  }
}

function runtimeFetch(path: string): typeof fetch {
  if (typeof globalThis.fetch === 'function') return globalThis.fetch.bind(globalThis);
  throw new NexusApiError(0, 'FetchUnavailable', path, 'fetch_unavailable', ['globalThis.fetch is not available'], 'Live adapter requires a fetch-capable runtime; use the mock adapter during SSR fallback.');
}

function requestHeaders(context: NexusApiClientContext, init?: RequestInit): Record<string, string> {
  return {
    accept: 'application/json',
    ...(init?.body ? { 'content-type': 'application/json' } : {}),
    ...(context.authToken ? { authorization: `Bearer ${context.authToken}` } : {}),
    ...(context.tenantId ? { 'x-trackmind-tenant-id': context.tenantId } : {}),
    ...(context.racetrackId ? { 'x-trackmind-racetrack-id': context.racetrackId } : {}),
    ...(context.requestId ? { 'x-trackmind-request-id': context.requestId } : {}),
    ...(context.headers ?? {}),
    ...((init?.headers as Record<string, string> | undefined) ?? {}),
  };
}

function isRequestInit(value: NexusApiClientContext | RequestInit): value is RequestInit {
  return 'method' in value || 'body' in value || 'signal' in value || 'credentials' in value || 'mode' in value || 'cache' in value || 'redirect' in value || 'referrerPolicy' in value || 'integrity' in value || 'keepalive' in value;
}

async function json<T>(baseUrl: string, path: string, context: NexusApiClientContext | RequestInit = {}, init?: RequestInit): Promise<T> {
  const requestContext = isRequestInit(context) ? {} : context;
  const requestInit = isRequestInit(context) ? context : init;
  const method = requestInit?.method ?? 'GET';
  const url = `${baseUrl}${path}`;
  let res: Response;
  try {
    res = await runtimeFetch(path)(url, { ...requestInit, headers: requestHeaders(requestContext, requestInit) });
  } catch (error) {
    if (error instanceof NexusApiError) throw error;
    const message = error instanceof Error ? error.message : String(error);
    throw new NexusApiError(0, 'NetworkError', path, 'request_failed', [message], 'Live TrackMind API request failed before a response was received.', { method, url });
  }
  if (!res.ok) {
    const apiError = await errorPayload(res);
    throw new NexusApiError(res.status, res.statusText, path, apiError?.code, apiError?.details, apiError?.message, { requestId: responseHeader(res, 'x-trackmind-request-id') ?? apiError?.requestId, timestamp: apiError?.timestamp, method, url });
  }
  try {
    return await res.json() as T;
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new NexusApiError(res.status, res.statusText || 'InvalidJson', path, 'invalid_json', [message], 'TrackMind API returned invalid JSON.', { requestId: responseHeader(res, 'x-trackmind-request-id'), method, url });
  }
}

